5	import {
6	  getBottomNestedBlockInfo,
7	  getNextBlockInfo,
8	  getParentBlockInfo,
9	  getPrevBlockInfo,
10	  mergeBlocksCommand,
11	} from "../../../api/blockManipulation/commands/mergeBlocks/mergeBlocks.js";
12	import { nestBlock } from "../../../api/blockManipulation/commands/nestBlock/nestBlock.js";
13	import { fixColumnList } from "../../../api/blockManipulation/commands/replaceBlocks/util/fixColumnList.js";
14	import { splitBlockCommand } from "../../../api/blockManipulation/commands/splitBlock/splitBlock.js";
15	import { updateBlockCommand } from "../../../api/blockManipulation/commands/updateBlock/updateBlock.js";
16	import {
17	  getBlockInfoFromResolvedPos,
18	  getBlockInfoFromSelection,
19	} from "../../../api/getBlockInfoFromPos.js";
20	import { BlockNoteEditor } from "../../../editor/BlockNoteEditor.js";
21	import { FormattingToolbarExtension } from "../../FormattingToolbar/FormattingToolbar.js";
22	import { FilePanelExtension } from "../../FilePanel/FilePanel.js";
23	
24	export const KeyboardShortcutsExtension = Extension.create<{
25	  editor: BlockNoteEditor<any, any, any>;
26	  tabBehavior: "prefer-navigate-ui" | "prefer-indent";
27	}>({
28	  priority: 50,
29	
30	  // TODO: The shortcuts need a refactor. Do we want to use a command priority
31	  //  design as there is now, or clump the logic into a single function?
32	  addKeyboardShortcuts() {
33	    // handleBackspace is partially adapted from https://github.com/ueberdosis/tiptap/blob/ed56337470efb4fd277128ab7ef792b37cfae992/packages/core/src/extensions/keymap.ts
34	    const handleBackspace = () =>
35	      this.editor.commands.first(({ chain, commands }) => [
36	        // Deletes the selection if it's not empty.
37	        () => commands.deleteSelection(),
38	        // Undoes an input rule if one was triggered in the last editor state change.
39	        () => commands.undoInputRule(),
40	        // Reverts block content type to a paragraph if the selection is at the start of the block.
41	        () =>
42	          commands.command(({ state }) => {
43	            const blockInfo = getBlockInfoFromSelection(state);
44	            if (!blockInfo.isBlockContainer) {
45	              return false;
46	            }
47	
48	            const selectionAtBlockStart =
49	              state.selection.from === blockInfo.blockContent.beforePos + 1;
50	            const isParagraph =
51	              blockInfo.blockContent.node.type.name === "paragraph";
52	
53	            if (selectionAtBlockStart && !isParagraph) {
54	              return commands.command(
55	                updateBlockCommand(blockInfo.bnBlock.beforePos, {
56	                  type: "paragraph",
57	                  props: {},
58	                }),
59	              );
60	            }
61	
62	            return false;
63	          }),
64	        // Removes a level of nesting if the block is indented if the selection is at the start of the block.
65	        () =>
66	          commands.command(({ state }) => {
67	            const blockInfo = getBlockInfoFromSelection(state);
68	            if (!blockInfo.isBlockContainer) {
69	              return false;
70	            }
71	            const { blockContent } = blockInfo;
72	
73	            const selectionAtBlockStart =
74	              state.selection.from === blockContent.beforePos + 1;
75	
76	            if (selectionAtBlockStart) {
77	              return commands.liftListItem("blockContainer");
78	            }
79	
80	            return false;
81	          }),
82	        // Merges block with the previous one if it isn't indented, and the selection is at the start of the
83	        // block. The target block for merging must contain inline content.
84	        () =>
85	          commands.command(({ state }) => {
86	            const blockInfo = getBlockInfoFromSelection(state);
87	            if (!blockInfo.isBlockContainer) {
88	              return false;
89	            }
90	            const { bnBlock: blockContainer, blockContent } = blockInfo;
91	
92	            const prevBlockInfo = getPrevBlockInfo(
93	              state.doc,
94	              blockInfo.bnBlock.beforePos,
95	            );
96	            // If the previous block has no inline content, it can't be merged.
97	            // It's instead deleted, which is done later in the chan, so we
98	            // return early here.
99	            if (
100	              !prevBlockInfo ||
101	              !prevBlockInfo.isBlockContainer ||
102	              prevBlockInfo.blockContent.node.type.spec.content !== "inline*"
103	            ) {
104	              return false;
105	            }
106	
107	            const selectionAtBlockStart =
108	              state.selection.from === blockContent.beforePos + 1;
109	            const selectionEmpty = state.selection.empty;
110	
111	            const posBetweenBlocks = blockContainer.beforePos;
112	
113	            if (selectionAtBlockStart && selectionEmpty) {
114	              return chain()
115	                .command(mergeBlocksCommand(posBetweenBlocks))
116	                .scrollIntoView()
117	                .run();
118	            }
119	
120	            return false;
121	          }),
122	        // If the previous block is a columnList, moves the current block to
123	        // the end of the last column in it.
124	        () =>
125	          commands.command(({ state, tr, dispatch }) => {
126	            const blockInfo = getBlockInfoFromSelection(state);
127	            if (!blockInfo.isBlockContainer) {
128	              return false;
129	            }
130	
131	            const prevBlockInfo = getPrevBlockInfo(
132	              state.doc,
133	              blockInfo.bnBlock.beforePos,
134	            );
135	            if (!prevBlockInfo || prevBlockInfo.isBlockContainer) {
136	              return false;
137	            }
138	
139	            if (dispatch) {
140	              const columnAfterPos = prevBlockInfo.bnBlock.afterPos - 1;
141	              const $blockAfterPos = tr.doc.resolve(columnAfterPos - 1);
142	
143	              tr.delete(
144	                blockInfo.bnBlock.beforePos,
145	                blockInfo.bnBlock.afterPos,
146	              );
147	              tr.insert($blockAfterPos.pos, blockInfo.bnBlock.node);
148	              tr.setSelection(
149	                TextSelection.near(tr.doc.resolve($blockAfterPos.pos + 1)),
150	              );
151	
152	              return true;
153	            }
154	
155	            return false;
156	          }),
157	        // If the block is the first in a column, moves it to the end of the
158	        // previous column. If there is no previous column, moves it above the
159	        // columnList.
160	        () =>
161	          commands.command(({ state, tr, dispatch }) => {
162	            const blockInfo = getBlockInfoFromSelection(state);
163	            if (!blockInfo.isBlockContainer) {
164	              return false;
165	            }
166	
167	            const selectionAtBlockStart =
168	              tr.selection.from === blockInfo.blockContent.beforePos + 1;
169	            if (!selectionAtBlockStart) {
170	              return false;
171	            }
172	
173	            const $pos = tr.doc.resolve(blockInfo.bnBlock.beforePos);
174	
175	            const prevBlock = $pos.nodeBefore;
176	            if (prevBlock) {
177	              return false;
178	            }
179	
180	            const parentBlock = $pos.node();
181	            if (parentBlock.type.name !== "column") {
182	              return false;
183	            }
184	
185	            const $blockPos = tr.doc.resolve(blockInfo.bnBlock.beforePos);
186	            const $columnPos = tr.doc.resolve($blockPos.before());
187	            const columnListPos = $columnPos.before();
188	
189	            if (dispatch) {
190	              tr.delete(
191	                blockInfo.bnBlock.beforePos,
192	                blockInfo.bnBlock.afterPos,
193	              );
194	              fixColumnList(tr, columnListPos);
195	
196	              if ($columnPos.pos === columnListPos + 1) {
197	                tr.insert(columnListPos, blockInfo.bnBlock.node);
198	                tr.setSelection(
199	                  TextSelection.near(tr.doc.resolve(columnListPos)),
200	                );
201	              } else {
202	                tr.insert($columnPos.pos - 1, blockInfo.bnBlock.node);
203	                tr.setSelection(
204	                  TextSelection.near(tr.doc.resolve($columnPos.pos)),
205	                );
206	              }
207	            }
208	
209	            return true;
210	          }),
211	        // Deletes the current block if it's an empty block with inline content,
212	        // and moves the selection to the previous block.
213	        () =>
214	          commands.command(({ state }) => {
215	            const blockInfo = getBlockInfoFromSelection(state);
216	            if (!blockInfo.isBlockContainer) {
217	              return false;
218	            }
219	
220	            const blockEmpty =
221	              blockInfo.blockContent.node.childCount === 0 &&
222	              blockInfo.blockContent.node.type.spec.content === "inline*";
223	
224	            if (blockEmpty) {
225	              const prevBlockInfo = getPrevBlockInfo(
226	                state.doc,
227	                blockInfo.bnBlock.beforePos,
228	              );
229	              if (!prevBlockInfo) {
230	                return false;
231	              }
232	              const bottomNestedPrevBlockInfo = getBottomNestedBlockInfo(
233	                state.doc,
234	                prevBlockInfo,
235	              );
236	              if (!bottomNestedPrevBlockInfo.isBlockContainer) {
237	                return false;
238	              }
239	              if (
240	                !bottomNestedPrevBlockInfo ||
241	                !bottomNestedPrevBlockInfo.isBlockContainer
242	              ) {
243	                return false;
244	              }
245	
246	              let chainedCommands = chain();
247	
248	              // Moves the children the current block.
249	              if (blockInfo.childContainer) {
250	                chainedCommands.insertContentAt(
251	                  blockInfo.bnBlock.afterPos,
252	                  blockInfo.childContainer?.node.content,
253	                );
254	              }
255	
256	              if (
257	                bottomNestedPrevBlockInfo.blockContent.node.type.spec
258	                  .content === "tableRow+"
259	              ) {
260	                const tableBlockEndPos = blockInfo.bnBlock.beforePos - 1;
261	                const tableBlockContentEndPos = tableBlockEndPos - 1;
262	                const lastRowEndPos = tableBlockContentEndPos - 1;
263	                const lastCellEndPos = lastRowEndPos - 1;
264	                const lastCellParagraphEndPos = lastCellEndPos - 1;
265	
266	                chainedCommands = chainedCommands.setTextSelection(
267	                  lastCellParagraphEndPos,
268	                );
269	              } else if (
270	                bottomNestedPrevBlockInfo.blockContent.node.type.spec
271	                  .content === ""
272	              ) {
273	                chainedCommands = chainedCommands.setNodeSelection(
274	                  bottomNestedPrevBlockInfo.blockContent.beforePos,
275	                );
276	              } else {
277	                const blockContentEndPos =
278	                  bottomNestedPrevBlockInfo.blockContent.afterPos - 1;
279	
280	                chainedCommands =
281	                  chainedCommands.setTextSelection(blockContentEndPos);
282	              }
283	
284	              return chainedCommands
285	                .deleteRange({
286	                  from: blockInfo.bnBlock.beforePos,
287	                  to: blockInfo.bnBlock.afterPos,
288	                })
289	                .scrollIntoView()
290	                .run();
291	            }
292	
293	            return false;
294	          }),
295	        // Deletes previous block if it contains no content and isn't a table,
296	        // when the selection is empty and at the start of the block. Moves the
297	        // current block into the deleted block's place.
298	        () =>
299	          commands.command(({ state }) => {
300	            const blockInfo = getBlockInfoFromSelection(state);
301	
302	            if (!blockInfo.isBlockContainer) {
303	              return false;
304	            }
305	
306	            const selectionAtBlockStart =
307	              state.selection.from === blockInfo.blockContent.beforePos + 1;
308	            const selectionEmpty = state.selection.empty;
309	
310	            const prevBlockInfo = getPrevBlockInfo(
311	              state.doc,
312	              blockInfo.bnBlock.beforePos,
313	            );
314	
315	            if (prevBlockInfo && selectionAtBlockStart && selectionEmpty) {
316	              const bottomBlock = getBottomNestedBlockInfo(
317	                state.doc,
318	                prevBlockInfo,
319	              );
320	
321	              if (!bottomBlock.isBlockContainer) {
322	                return false;
323	              }
324	
325	              const prevBlockNotTableAndNoContent =
326	                bottomBlock.blockContent.node.type.spec.content === "" ||
327	                (bottomBlock.blockContent.node.type.spec.content ===
328	                  "inline*" &&
329	                  bottomBlock.blockContent.node.childCount === 0);
330	
331	              if (prevBlockNotTableAndNoContent) {
332	                return chain()
333	                  .cut(
334	                    {
335	                      from: blockInfo.bnBlock.beforePos,
336	                      to: blockInfo.bnBlock.afterPos,
337	                    },
338	                    bottomBlock.bnBlock.afterPos,
339	                  )
340	                  .deleteRange({
341	                    from: bottomBlock.bnBlock.beforePos,
342	                    to: bottomBlock.bnBlock.afterPos,
343	                  })
344	                  .run();
345	              }
346	            }
347	
348	            return false;
349	          }),
350	      ]);
351	
352	    const handleDelete = () =>
353	      this.editor.commands.first(({ chain, commands }) => [
354	        // Deletes the selection if it's not empty.
355	        () => commands.deleteSelection(),
356	        // Deletes the first child block and un-nests its children, if the
357	        // selection is empty and at the end of the current block. If both the
358	        // parent and child blocks have inline content, the child block's
359	        // content is appended to the parent's. The child block's own children
360	        // are unindented before it's deleted.
361	        () =>
362	          commands.command(({ state }) => {
363	            const blockInfo = getBlockInfoFromSelection(state);
364	            if (!blockInfo.isBlockContainer || !blockInfo.childContainer) {
365	              return false;
366	            }
367	            const { blockContent, childContainer } = blockInfo;
368	
369	            const selectionAtBlockEnd =
370	              state.selection.from === blockContent.afterPos - 1;
371	            const selectionEmpty = state.selection.empty;
372	
373	            const firstChildBlockInfo = getBlockInfoFromResolvedPos(
374	              state.doc.resolve(childContainer.beforePos + 1),
375	            );
376	            if (!firstChildBlockInfo.isBlockContainer) {
377	              return false;
378	            }
379	
380	            if (selectionAtBlockEnd && selectionEmpty) {
381	              const firstChildBlockContent =
382	                firstChildBlockInfo.blockContent.node;
383	              const firstChildBlockHasInlineContent =
384	                firstChildBlockContent.type.spec.content === "inline*";
385	              const blockHasInlineContent =
386	                blockContent.node.type.spec.content === "inline*";
387	
388	              return (
389	                chain()
390	                  // Un-nests child block's children if necessary.
391	                  .insertContentAt(
392	                    firstChildBlockInfo.bnBlock.afterPos,
393	                    firstChildBlockInfo.childContainer?.node.content ||
394	                      Fragment.empty,
395	                  )
396	                  .deleteRange(
397	                    // Deletes whole child container if there's only one child.
398	                    childContainer.node.childCount === 1
399	                      ? {
400	                          from: childContainer.beforePos,
401	                          to: childContainer.afterPos,
402	                        }
403	                      : {
404	                          from: firstChildBlockInfo.bnBlock.beforePos,
405	                          to: firstChildBlockInfo.bnBlock.afterPos,
406	                        },
407	                  )
408	                  // Appends inline content from child block if possible.
409	                  .insertContentAt(
410	                    state.selection.from,
411	                    firstChildBlockHasInlineContent && blockHasInlineContent
412	                      ? firstChildBlockContent.content
413	                      : null,
414	                  )
415	                  .setTextSelection(state.selection.from)
416	                  .scrollIntoView()
417	                  .run()
418	              );
419	            }
420	
421	            return false;
422	          }),
423	        // Merges block with the next one (at the same nesting level or lower),
424	        // if one exists, the block has no children, and the selection is at the
425	        // end of the block.
426	        () =>
427	          commands.command(({ state }) => {
428	            const blockInfo = getBlockInfoFromSelection(state);
429	            if (!blockInfo.isBlockContainer) {
430	              return false;
431	            }
432	            const { bnBlock: blockContainer, blockContent } = blockInfo;
433	
434	            const nextBlockInfo = getNextBlockInfo(
435	              state.doc,
436	              blockInfo.bnBlock.beforePos,
437	            );
438	            if (!nextBlockInfo || !nextBlockInfo.isBlockContainer) {
439	              return false;
440	            }
441	
442	            const selectionAtBlockEnd =
443	              state.selection.from === blockContent.afterPos - 1;
444	            const selectionEmpty = state.selection.empty;
445	
446	            const posBetweenBlocks = blockContainer.afterPos;
447	
448	            if (selectionAtBlockEnd && selectionEmpty) {
449	              return chain()
450	                .command(mergeBlocksCommand(posBetweenBlocks))
451	                .scrollIntoView()
452	                .run();
453	            }
454	
455	            return false;
456	          }),
457	        // If the previous block is a columnList, moves the current block to
458	        // the end of the last column in it.
459	        () =>
460	          commands.command(({ state, tr, dispatch }) => {
461	            const blockInfo = getBlockInfoFromSelection(state);
462	            if (!blockInfo.isBlockContainer) {
463	              return false;
464	            }
465	
466	            const nextBlockInfo = getNextBlockInfo(
467	              state.doc,
468	              blockInfo.bnBlock.beforePos,
469	            );
470	            if (!nextBlockInfo || nextBlockInfo.isBlockContainer) {
471	              return false;
472	            }
473	
474	            if (dispatch) {
475	              const columnBeforePos = nextBlockInfo.bnBlock.beforePos + 1;
476	              const $blockBeforePos = tr.doc.resolve(columnBeforePos + 1);
477	
478	              tr.delete(
479	                $blockBeforePos.pos,
480	                $blockBeforePos.pos + $blockBeforePos.nodeAfter!.nodeSize,
481	              );
482	              fixColumnList(tr, nextBlockInfo.bnBlock.beforePos);
483	              tr.insert(blockInfo.bnBlock.afterPos, $blockBeforePos.nodeAfter!);
484	              tr.setSelection(
485	                TextSelection.near(tr.doc.resolve($blockBeforePos.pos)),
486	              );
487	
488	              return true;
489	            }
490	
491	            return false;
492	          }),
493	        // If the block is the last in a column, moves it to the start of the
494	        // next column. If there is no next column, moves it below the
495	        // columnList.
496	        () =>
497	          commands.command(({ state, tr, dispatch }) => {
498	            const blockInfo = getBlockInfoFromSelection(state);
499	            if (!blockInfo.isBlockContainer) {
500	              return false;
501	            }
502	
503	            const selectionAtBlockEnd =
504	              tr.selection.from === blockInfo.blockContent.afterPos - 1;
505	            if (!selectionAtBlockEnd) {
506	              return false;
507	            }
508	
509	            const $pos = tr.doc.resolve(blockInfo.bnBlock.afterPos);
510	
511	            const nextBlock = $pos.nodeAfter;
512	            if (nextBlock) {
513	              return false;
514	            }
515	
516	            const parentBlock = $pos.node();
517	            if (parentBlock.type.name !== "column") {
518	              return false;
519	            }
520	
521	            const $blockEndPos = tr.doc.resolve(blockInfo.bnBlock.afterPos);
522	            const $columnEndPos = tr.doc.resolve($blockEndPos.after());
523	            const columnListEndPos = $columnEndPos.after();
524	
525	            if (dispatch) {
526	              // Position before first block in next column, or first block
527	              // after columnList if there is no next column.
528	              const nextBlockBeforePos =
529	                $columnEndPos.pos === columnListEndPos - 1
530	                  ? columnListEndPos
531	                  : $columnEndPos.pos + 1;
532	              const nextBlockInfo = getBlockInfoFromResolvedPos(
533	                tr.doc.resolve(nextBlockBeforePos),
534	              );
535	
536	              tr.delete(
537	                nextBlockInfo.bnBlock.beforePos,
538	                nextBlockInfo.bnBlock.afterPos,
539	              );
540	              fixColumnList(
541	                tr,
542	                columnListEndPos - $columnEndPos.node().nodeSize,
543	              );
544	              tr.insert($blockEndPos.pos, nextBlockInfo.bnBlock.node);
545	              tr.setSelection(
546	                TextSelection.near(tr.doc.resolve(nextBlockBeforePos)),
547	              );
548	            }
549	
550	            return true;
551	          }),
552	        // Deletes the next block at either the same or lower nesting level, if
553	        // the selection is empty and at the end of the block. If both the
554	        // current and next blocks have inline content, the next block's
555	        // content is appended to the current block's. The next block's own
556	        // children are unindented before it's deleted.
557	        () =>
558	          commands.command(({ state }) => {
559	            const blockInfo = getBlockInfoFromSelection(state);
560	            if (!blockInfo.isBlockContainer) {
561	              return false;
562	            }
563	            const { blockContent } = blockInfo;
564	
565	            const selectionAtBlockEnd =
566	              state.selection.from === blockContent.afterPos - 1;
567	            const selectionEmpty = state.selection.empty;
568	
569	            if (selectionAtBlockEnd && selectionEmpty) {
570	              const getNextBlockInfoAtAnyLevel = (
571	                doc: Node,
572	                beforePos: number,
573	              ) => {
574	                const nextBlockInfo = getNextBlockInfo(doc, beforePos);
575	                if (nextBlockInfo) {
576	                  return nextBlockInfo;
577	                }
578	
579	                const parentBlockInfo = getParentBlockInfo(doc, beforePos);
580	                if (!parentBlockInfo) {
581	                  return undefined;
582	                }
583	
584	                return getNextBlockInfoAtAnyLevel(
585	                  doc,
586	                  parentBlockInfo.bnBlock.beforePos,
587	                );
588	              };
589	
590	              const nextBlockInfo = getNextBlockInfoAtAnyLevel(
591	                state.doc,
592	                blockInfo.bnBlock.beforePos,
593	              );
594	              if (!nextBlockInfo || !nextBlockInfo.isBlockContainer) {
595	                return false;
596	              }
597	
598	              const nextBlockContent = nextBlockInfo.blockContent.node;
599	              const nextBlockHasInlineContent =
600	                nextBlockContent.type.spec.content === "inline*";
601	              const blockHasInlineContent =
602	                blockContent.node.type.spec.content === "inline*";
603	
604	              return (
605	                chain()
606	                  // Un-nests next block's children if necessary.
607	                  .insertContentAt(
608	                    nextBlockInfo.bnBlock.afterPos,
609	                    nextBlockInfo.childContainer?.node.content ||
610	                      Fragment.empty,
611	                  )
612	                  .deleteRange({
613	                    from: nextBlockInfo.bnBlock.beforePos,
614	                    to: nextBlockInfo.bnBlock.afterPos,
615	                  })
616	                  // Appends inline content from child block if possible.
617	                  .insertContentAt(
618	                    state.selection.from,
619	                    nextBlockHasInlineContent && blockHasInlineContent
620	                      ? nextBlockContent.content
621	                      : null,
622	                  )
623	                  .setTextSelection(state.selection.from)
624	                  .scrollIntoView()
625	                  .run()
626	              );
627	            }
628	
629	            return false;
630	          }),
631	        // Deletes the current block if it's an empty block with inline content,
632	        // and moves the selection to the next block.
633	        () =>
634	          commands.command(({ state }) => {
635	            const blockInfo = getBlockInfoFromSelection(state);
636	            if (!blockInfo.isBlockContainer) {
637	              return false;
638	            }
639	
640	            const blockEmpty =
641	              blockInfo.blockContent.node.childCount === 0 &&
642	              blockInfo.blockContent.node.type.spec.content === "inline*";
643	
644	            if (blockEmpty) {
645	              const nextBlockInfo = getNextBlockInfo(
646	                state.doc,
647	                blockInfo.bnBlock.beforePos,
648	              );
649	              if (!nextBlockInfo || !nextBlockInfo.isBlockContainer) {
650	                return false;
651	              }
652	
653	              let chainedCommands = chain();
654	
655	              if (
656	                nextBlockInfo.blockContent.node.type.spec.content ===
657	                "tableRow+"
658	              ) {
659	                const tableBlockStartPos = blockInfo.bnBlock.afterPos + 1;
660	                const tableBlockContentStartPos = tableBlockStartPos + 1;
661	                const firstRowStartPos = tableBlockContentStartPos + 1;
662	                const firstCellStartPos = firstRowStartPos + 1;
663	                const firstCellParagraphStartPos = firstCellStartPos + 1;
664	
665	                chainedCommands = chainedCommands.setTextSelection(
666	                  firstCellParagraphStartPos,
667	                );
668	              } else if (
669	                nextBlockInfo.blockContent.node.type.spec.content === ""
670	              ) {
671	                chainedCommands = chainedCommands.setNodeSelection(
672	                  nextBlockInfo.blockContent.beforePos,
673	                );
674	              } else {
675	                chainedCommands = chainedCommands.setTextSelection(
676	                  nextBlockInfo.blockContent.beforePos + 1,
677	                );
678	              }
679	
680	              return chainedCommands
681	                .deleteRange({
682	                  from: blockInfo.bnBlock.beforePos,
683	                  to: blockInfo.bnBlock.afterPos,
684	                })
685	                .scrollIntoView()
686	                .run();
687	            }
688	
689	            return false;
690	          }),
691	        // Deletes next block if it contains no content and isn't a table,
692	        // when the selection is empty and at the end of the block. Moves the
693	        // current block into the deleted block's place.
694	        () =>
695	          commands.command(({ state }) => {
696	            const blockInfo = getBlockInfoFromSelection(state);
697	
698	            if (!blockInfo.isBlockContainer) {
699	              return false;
700	            }
701	
702	            const selectionAtBlockEnd =
703	              state.selection.from === blockInfo.blockContent.afterPos - 1;
704	            const selectionEmpty = state.selection.empty;
705	
706	            const nextBlockInfo = getNextBlockInfo(
707	              state.doc,
708	              blockInfo.bnBlock.beforePos,
709	            );
710	            if (!nextBlockInfo) {
711	              return false;
712	            }
713	            if (!nextBlockInfo.isBlockContainer) {
714	              return false;
715	            }
716	
717	            if (nextBlockInfo && selectionAtBlockEnd && selectionEmpty) {
718	              const nextBlockNotTableAndNoContent =
719	                nextBlockInfo.blockContent.node.type.spec.content === "" ||
720	                (nextBlockInfo.blockContent.node.type.spec.content ===
721	                  "inline*" &&
722	                  nextBlockInfo.blockContent.node.childCount === 0);
723	
724	              if (nextBlockNotTableAndNoContent) {
725	                const childBlocks =
726	                  nextBlockInfo.bnBlock.node.lastChild!.content;
727	                return chain()
728	                  .deleteRange({
729	                    from: nextBlockInfo.bnBlock.beforePos,
730	                    to: nextBlockInfo.bnBlock.afterPos,
731	                  })
732	                  .insertContentAt(
733	                    blockInfo.bnBlock.afterPos,
734	                    nextBlockInfo.bnBlock.node.childCount === 2
735	                      ? childBlocks
736	                      : null,
737	                  )
738	                  .run();
739	              }
740	            }
741	
742	            return false;
743	          }),
744	      ]);
745	
746	    const handleEnter = (withShift = false) => {
747	      return this.editor.commands.first(({ commands, tr }) => [
748	        // Removes a level of nesting if the block is empty & indented, while the selection is also empty & at the start
749	        // of the block.
750	        () =>
751	          commands.command(({ state }) => {
752	            const blockInfo = getBlockInfoFromSelection(state);
753	            if (!blockInfo.isBlockContainer) {
754	              return false;
755	            }
756	            const { bnBlock: blockContainer, blockContent } = blockInfo;
757	
758	            const { depth } = state.doc.resolve(blockContainer.beforePos);
759	
760	            const selectionAtBlockStart =
761	              state.selection.$anchor.parentOffset === 0;
762	            const selectionEmpty =
763	              state.selection.anchor === state.selection.head;
764	            const blockEmpty = blockContent.node.childCount === 0;
765	            const blockIndented = depth > 1;
766	
767	            if (
768	              selectionAtBlockStart &&
769	              selectionEmpty &&
770	              blockEmpty &&
771	              blockIndented
772	            ) {
773	              return commands.liftListItem("blockContainer");
774	            }
775	
776	            return false;
777	          }),
778	        // Creates a hard break if block is configured to do so.
779	        () =>
780	          commands.command(({ state }) => {
781	            const blockInfo = getBlockInfoFromSelection(state);
782	
783	            const blockHardBreakShortcut =
784	              this.options.editor.schema.blockSchema[
785	                blockInfo.blockNoteType as keyof typeof this.options.editor.schema.blockSchema
786	              ].meta?.hardBreakShortcut ?? "shift+enter";
787	
788	            if (blockHardBreakShortcut === "none") {
789	              return false;
790	            }
791	
792	            if (
793	              // If shortcut is not configured, or is configured as "shift+enter",
794	              // create a hard break for shift+enter, but not for enter.
795	              (blockHardBreakShortcut === "shift+enter" && withShift) ||
796	              // If shortcut is configured as "enter", create a hard break for
797	              // both enter and shift+enter.
798	              blockHardBreakShortcut === "enter"
799	            ) {
800	              const marks =
801	                tr.storedMarks ||
802	                tr.selection.$head
803	                  .marks()
804	                  .filter((m) =>
805	                    this.editor.extensionManager.splittableMarks.includes(
806	                      m.type.name,
807	                    ),
808	                  );
809	
810	              tr.insert(
811	                tr.selection.head,
812	                tr.doc.type.schema.nodes.hardBreak.create(),
813	              ).ensureMarks(marks);
814	              return true;
815	            }
816	
817	            return false;
818	          }),
819	        // Creates a new block and moves the selection to it if the current one is empty, while the selection is also
820	        // empty & at the start of the block.
821	        () =>
822	          commands.command(({ state, dispatch, tr }) => {
823	            const blockInfo = getBlockInfoFromSelection(state);
824	            if (!blockInfo.isBlockContainer) {
825	              return false;
826	            }
827	            const { bnBlock: blockContainer, blockContent } = blockInfo;
828	
829	            const selectionAtBlockStart =
830	              state.selection.$anchor.parentOffset === 0;
831	            const selectionEmpty =
832	              state.selection.anchor === state.selection.head;
833	            const blockEmpty = blockContent.node.childCount === 0;
834	
835	            if (selectionAtBlockStart && selectionEmpty && blockEmpty) {
836	              const newBlockInsertionPos = blockContainer.afterPos;
837	              const newBlockContentPos = newBlockInsertionPos + 2;
838	
839	              if (dispatch) {
840	                // Creates a new block with the children of the current block,
841	                // if it has any.
842	                const newBlock = state.schema.nodes[
843	                  "blockContainer"
844	                ].createAndFill(
845	                  undefined,
846	                  [
847	                    state.schema.nodes["paragraph"].createAndFill() ||
848	                      undefined,
849	                    blockInfo.childContainer?.node,
850	                  ].filter((node) => node !== undefined),
851	                )!;
852	
853	                // Inserts the new block and moves the selection to it.
854	                tr.insert(newBlockInsertionPos, newBlock)
855	                  .setSelection(
856	                    new TextSelection(tr.doc.resolve(newBlockContentPos)),
857	                  )
858	                  .scrollIntoView();
859	
860	                // Deletes old block's children, as they have been moved to
861	                // the new one.
862	                if (blockInfo.childContainer) {
863	                  tr.delete(
864	                    blockInfo.childContainer.beforePos,
865	                    blockInfo.childContainer.afterPos,
866	                  );
867	                }
868	              }
869	
870	              return true;
871	            }
872	
873	            return false;
874	          }),
875	        // Splits the current block, moving content inside that's after the cursor to a new text block below. Also
876	        // deletes the selection beforehand, if it's not empty.
877	        () =>
878	          commands.command(({ state, chain }) => {
879	            const blockInfo = getBlockInfoFromSelection(state);
880	            if (!blockInfo.isBlockContainer) {
881	              return false;
882	            }
883	            const { blockContent } = blockInfo;
884	
885	            const selectionAtBlockStart =
886	              state.selection.$anchor.parentOffset === 0;
887	            const blockEmpty = blockContent.node.childCount === 0;
888	
889	            if (!blockEmpty) {
890	              chain()
891	                .deleteSelection()
892	                .command(
893	                  splitBlockCommand(
894	                    state.selection.from,
895	                    selectionAtBlockStart,
896	                    selectionAtBlockStart,
897	                  ),
898	                )
899	                .run();
900	
901	              return true;
902	            }
903	
904	            return false;
905	          }),
906	      ]);
907	    };
908	
909	    return {
910	      Backspace: handleBackspace,
911	      Delete: handleDelete,
912	      Enter: () => handleEnter(),
