1	import { isNodeSelection, posToDOMRect } from "@tiptap/core";
2	import {
3	  getSelection,
4	  getSelectionCutBlocks,
5	  setSelection,
6	} from "../../api/blockManipulation/selections/selection.js";
7	import {
8	  getTextCursorPosition,
9	  setTextCursorPosition,
10	} from "../../api/blockManipulation/selections/textCursorPosition.js";
11	import {
12	  DefaultBlockSchema,
13	  DefaultInlineContentSchema,
14	  DefaultStyleSchema,
15	} from "../../blocks/defaultBlocks.js";
16	import {
17	  BlockIdentifier,
18	  BlockSchema,
19	  InlineContentSchema,
20	  StyleSchema,
21	} from "../../schema/index.js";
22	import { BlockNoteEditor } from "../BlockNoteEditor.js";
23	import { TextCursorPosition } from "../cursorPositionTypes.js";
24	import { Selection } from "../selectionTypes.js";
25	
26	export class SelectionManager<
27	  BSchema extends BlockSchema = DefaultBlockSchema,
28	  ISchema extends InlineContentSchema = DefaultInlineContentSchema,
29	  SSchema extends StyleSchema = DefaultStyleSchema,
30	> {
31	  constructor(private editor: BlockNoteEditor<BSchema, ISchema, SSchema>) {}
32	
33	  /**
34	   * Gets a snapshot of the current selection. This contains all blocks (included nested blocks)
35	   * that the selection spans across.
36	   *
37	   * If the selection starts / ends halfway through a block, the returned data will contain the entire block.
38	   */
39	  public getSelection(): Selection<BSchema, ISchema, SSchema> | undefined {
40	    return this.editor.transact((tr) => getSelection(tr));
41	  }
42	
43	  /**
44	   * Gets a snapshot of the current selection. This contains all blocks (included nested blocks)
45	   * that the selection spans across.
46	   *
47	   * If the selection starts / ends halfway through a block, the returned block will be
48	   * only the part of the block that is included in the selection.
49	   */
50	  public getSelectionCutBlocks(expandToWords = false) {
51	    return this.editor.transact((tr) =>
52	      getSelectionCutBlocks(tr, expandToWords),
53	    );
54	  }
55	
56	  /**
57	   * Sets the selection to a range of blocks.
58	   * @param startBlock The identifier of the block that should be the start of the selection.
59	   * @param endBlock The identifier of the block that should be the end of the selection.
60	   */
61	  public setSelection(startBlock: BlockIdentifier, endBlock: BlockIdentifier) {
62	    return this.editor.transact((tr) => setSelection(tr, startBlock, endBlock));
63	  }
64	
65	  /**
66	   * Gets a snapshot of the current text cursor position.
67	   * @returns A snapshot of the current text cursor position.
68	   */
69	  public getTextCursorPosition(): TextCursorPosition<
70	    BSchema,
71	    ISchema,
72	    SSchema
73	  > {
74	    return this.editor.transact((tr) => getTextCursorPosition(tr));
75	  }
76	
77	  /**
78	   * Sets the text cursor position to the start or end of an existing block. Throws an error if the target block could
79	   * not be found.
80	   * @param targetBlock The identifier of an existing block that the text cursor should be moved to.
81	   * @param placement Whether the text cursor should be placed at the start or end of the block.
82	   */
83	  public setTextCursorPosition(
84	    targetBlock: BlockIdentifier,
85	    placement: "start" | "end" = "start",
86	  ) {
87	    return this.editor.transact((tr) =>
88	      setTextCursorPosition(tr, targetBlock, placement),
89	    );
90	  }
91	
92	  /**
93	   * Gets the bounding box of the current selection.
94	   */
95	  public getSelectionBoundingBox() {
96	    if (!this.editor.prosemirrorView) {
97	      return undefined;
