import { describe, expect, it } from "vitest";

import { setupTestEnv } from "../setupTestEnv.js";

const getEditor = setupTestEnv();

describe("Test removeBlocks", () => {
  it("does not move an empty block after a column list while backspacing", () => {
    const editor = getEditor();

    editor.updateBlock("paragraph-2", { content: "" });
    editor.setTextCursorPosition("paragraph-2", "start");

    editor._tiptapEditor.commands.keyboardShortcut("Backspace");

    expect(editor.document.find((block) => block.id === "column-list-0"))
      .toMatchInlineSnapshot(`
        {
          "children": [
            {
              "children": [
                {
                  "children": [],
                  "content": [
                    {
                      "styles": {},
                      "text": "Column Paragraph 0",
                      "type": "text",
                    },
                  ],
                  "id": "column-paragraph-0",
                  "props": {
                    "backgroundColor": "default",
                    "textAlignment": "left",
                    "textColor": "default",
                  },
                  "type": "paragraph",
                },
                {
                  "children": [],
                  "content": [
                    {
                      "styles": {},
                      "text": "Column Paragraph 1",
                      "type": "text",
                    },
                  ],
                  "id": "column-paragraph-1",
                  "props": {
                    "backgroundColor": "default",
                    "textAlignment": "left",
                    "textColor": "default",
                  },
                  "type": "paragraph",
                },
              ],
              "content": undefined,
              "id": "column-0",
              "props": {
                "width": 1,
              },
              "type": "column",
            },
            {
              "children": [
                {
                  "children": [],
                  "content": [
                    {
                      "styles": {},
                      "text": "Column Paragraph 2",
                      "type": "text",
                    },
                  ],
                  "id": "column-paragraph-2",
                  "props": {
                    "backgroundColor": "default",
                    "textAlignment": "left",
                    "textColor": "default",
                  },
                  "type": "paragraph",
                },
                {
                  "children": [],
                  "content": [
                    {
                      "styles": {},
                      "text": "Column Paragraph 3",
                      "type": "text",
                    },
                  ],
                  "id": "column-paragraph-3",
                  "props": {
                    "backgroundColor": "default",
                    "textAlignment": "left",
                    "textColor": "default",
                  },
                  "type": "paragraph",
                },
              ],
              "content": undefined,
              "id": "column-1",
              "props": {
                "width": 1,
              },
              "type": "column",
            },
          ],
          "content": undefined,
          "id": "column-list-0",
          "props": {},
          "type": "columnList",
        }
      `);
    expect(editor.getBlock("paragraph-2")?.content).toEqual([]);
    expect(editor.getTextCursorPosition().block.id).toBe("paragraph-2");
  });

  it("Remove all blocks in column", () => {
    getEditor().removeBlocks(["column-paragraph-0", "column-paragraph-1"]);

    expect(getEditor().document).toMatchSnapshot();
  });

  it("Remove all blocks in second column", () => {
    getEditor().removeBlocks(["column-paragraph-2", "column-paragraph-3"]);

    expect(getEditor().document).toMatchSnapshot();
  });

  it("Remove all blocks in columns", () => {
    getEditor().removeBlocks([
      "column-paragraph-0",
      "column-paragraph-1",
      "column-paragraph-2",
      "column-paragraph-3",
    ]);

    expect(getEditor().document).toMatchSnapshot();
  });

  it("Remove column in columnList", () => {
    getEditor().removeBlocks(["column-0"]);

    expect(getEditor().document).toMatchSnapshot();
  });

  it("Remove all columns in columnList", () => {
    getEditor().removeBlocks(["column-0", "column-1"]);

    expect(getEditor().document).toMatchSnapshot();
  });

  it("Remove all blocks in column and block after", () => {
    getEditor().removeBlocks([
      "column-paragraph-0",
      "column-paragraph-1",
      "paragraph-2",
    ]);

    expect(getEditor().document).toMatchSnapshot();
  });

  it("Remove all blocks in columns and block after", () => {
    getEditor().removeBlocks([
      "column-paragraph-0",
      "column-paragraph-1",
      "column-paragraph-2",
      "column-paragraph-3",
      "paragraph-2",
    ]);

    expect(getEditor().document).toMatchSnapshot();
  });

  it("Remove column in columnList and block after", () => {
    getEditor().removeBlocks(["column-0", "paragraph-2"]);

    expect(getEditor().document).toMatchSnapshot();
  });

  it("Remove all columns in columnList and block after", () => {
    getEditor().removeBlocks(["column-0", "column-1", "paragraph-2"]);

    expect(getEditor().document).toMatchSnapshot();
  });

  it("Remove column and and block in column after", () => {
    getEditor().removeBlocks(["column-0", "column-paragraph-2"]);

    expect(getEditor().document).toMatchSnapshot();
  });
});

